import { useState, useMemo } from "react";
import { Outlet, useNavigate, Link, useLocation } from "react-router-dom";
import { authService } from "@/App";
import { Button } from "@/components/ui/button";
import {
  LayoutDashboard, Users, UsersRound, CreditCard, CalendarCheck,
  GraduationCap, Calendar, Package, LogOut, Menu, X, Building2,
  Bell, User, FileText
} from "lucide-react";

const DashboardLayout = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // =========================
  // SAFE USER + ROLE FIX
  // =========================
  const rawUser = authService.getUser() || {};

  const normalizeRole = (r) => {
    if (!r) return "";

    const role = r.toString().toLowerCase();

    // 🔥 ROLE MAPPING FIX (CRITICAL)
    if (role === "admin") return "school_admin";
    if (role === "super_admin") return "super_admin";
    if (role === "superadmin") return "super_admin";
    if (role === "schooladmin") return "school_admin";

    return role;
  };

  const user = {
    ...rawUser,
    role: normalizeRole(rawUser.role),
  };

  const role = user.role;

  const handleLogout = () => {
    authService.clearAuth();
    navigate("/login");
  };

  const menuItems = [
    { icon: LayoutDashboard, label: "Dashboard", path: "/app/dashboard", roles: ["super_admin", "school_admin", "teacher", "finance", "secretary"] },
    { icon: Building2, label: "Super Admin", path: "/app/super-admin", roles: ["super_admin"] },
    { icon: Building2, label: "School Profile", path: "/app/school-profile", roles: ["school_admin"] },
    { icon: Users, label: "Students", path: "/app/students", roles: ["school_admin", "teacher"] },
    { icon: UsersRound, label: "Staff", path: "/app/staff", roles: ["school_admin"] },
    { icon: CreditCard, label: "Fees", path: "/app/fees", roles: ["school_admin", "finance"] },
    { icon: CalendarCheck, label: "Attendance", path: "/app/attendance", roles: ["school_admin", "teacher"] },
    { icon: GraduationCap, label: "Performance", path: "/app/exams", roles: ["school_admin", "teacher"] },
    { icon: Bell, label: "Announcements", path: "/app/announcements", roles: ["school_admin", "teacher", "secretary"] },
    { icon: User, label: "Teacher Portal", path: "/app/teacher-portal", roles: ["teacher"] },
    { icon: CreditCard, label: "Finance Portal", path: "/app/finance-portal", roles: ["finance"] },
    { icon: FileText, label: "Secretary Portal", path: "/app/secretary-portal", roles: ["secretary"] },
    { icon: User, label: "Student Portal", path: "/app/student-portal", roles: ["student", "parent"] },
    { icon: Calendar, label: "Timetable", path: "/app/timetable", roles: ["school_admin", "teacher"] },
    { icon: Package, label: "Inventory", path: "/app/inventory", roles: ["school_admin"] },
  ];

  // =========================
  // SAFE MENU FILTER (FIXED)
  // =========================
  const visibleItems = useMemo(() => {
    if (!role) return [];

    return menuItems.filter(item =>
      Array.isArray(item.roles) &&
      item.roles.includes(role)
    );
  }, [role]);

  const isActive = (path) =>
    location.pathname === path || location.pathname.startsWith(path);

  return (
    <div className="flex h-screen bg-[#0B1220] text-slate-200">

      {/* SIDEBAR */}
      <aside
        className={`fixed lg:static inset-y-0 left-0 z-50 w-64 bg-[#0F172A]/95 backdrop-blur-xl border-r border-white/5 transition-transform duration-200 ${
          sidebarOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0"
        }`}
      >

        {/* LOGO */}
        <div className="h-16 flex items-center justify-between px-5 border-b border-white/5">
          <div className="flex items-center gap-3">
            <div className="w-9 h-9 bg-emerald-500/15 rounded-lg flex items-center justify-center border border-emerald-500/20">
              <GraduationCap className="w-5 h-5 text-emerald-400" />
            </div>
            <span className="text-white font-semibold tracking-wide">
              Smart-M Hub
            </span>
          </div>

          <button
            className="lg:hidden text-slate-400 hover:text-white"
            onClick={() => setSidebarOpen(false)}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* NAV */}
        <nav className="p-3 space-y-1 overflow-y-auto">
          {visibleItems.length > 0 ? (
            visibleItems.map(item => {
              const Icon = item.icon;

              return (
                <Link
                  key={item.path}
                  to={item.path}
                  onClick={() => setSidebarOpen(false)}
                  className={`relative flex items-center gap-3 px-3 py-2.5 rounded-lg transition-all text-sm ${
                    isActive(item.path)
                      ? "bg-white/5 text-emerald-400"
                      : "text-slate-400 hover:text-white hover:bg-white/5"
                  }`}
                >
                  {isActive(item.path) && (
                    <div className="absolute left-0 top-2 bottom-2 w-1 bg-emerald-400 rounded-full" />
                  )}

                  <Icon className="w-[18px] h-[18px]" />
                  <span className="font-medium">{item.label}</span>
                </Link>
              );
            })
          ) : (
            <div className="text-sm text-red-400 px-3">
              No menu available (role: {role || "undefined"})
            </div>
          )}
        </nav>

        {/* USER */}
        <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-white/5">
          <div className="mb-3">
            <p className="text-sm text-white font-medium truncate">
              {user.full_name || "Guest User"}
            </p>
            <p className="text-xs text-slate-500 truncate">
              {user.email || "No email"}
            </p>
          </div>

          <Button
            variant="ghost"
            onClick={handleLogout}
            className="w-full justify-start text-slate-400 hover:text-red-400 hover:bg-red-500/10"
          >
            <LogOut className="w-4 h-4 mr-2" />
            Logout
          </Button>
        </div>
      </aside>

      {/* MAIN */}
      <div className="flex-1 flex flex-col">

        {/* HEADER */}
        <header className="h-14 bg-[#0F172A]/80 backdrop-blur-xl border-b border-white/5 flex items-center justify-between px-5">

          <button
            className="lg:hidden text-slate-400 hover:text-white"
            onClick={() => setSidebarOpen(true)}
          >
            <Menu className="w-5 h-5" />
          </button>

          <h1 className="text-sm text-slate-300">
            Welcome back, <span className="text-white">{user.full_name || "User"}</span>
          </h1>

          <div className="flex items-center gap-2">
            <span className="text-xs px-3 py-1 rounded-full bg-emerald-500/10 text-emerald-400 border border-emerald-500/20 uppercase tracking-wider">
              {role || "no-role"}
            </span>
          </div>

        </header>

        {/* CONTENT */}
        <main className="flex-1 overflow-auto p-6 lg:p-8 bg-[#0B1220]">
          <Outlet />
        </main>

      </div>
    </div>
  );
};

export default DashboardLayout;
